{{#switch:{{{form|}}}
 |editnotice = {{editnotice
  |id    = {{{id|}}}
  |image = [[Image:Ambox warning yellow.svg|40x40px|alt=|link=]]
  |text  = {{Interconnected template/text|{{{1|}}}|{{{2|}}}|{{{3|}}}|{{{4|}}}|page={{{page|}}}}}
  |expiry= {{{expiry|}}}
 }}
 |#default = {{ombox
  |type  = style
  |image = [[Image:Ambox warning yellow.svg|40x40px|alt=|link=]]
  |text  = {{Interconnected template/text|{{{1|<noinclude>other page1</noinclude>}}}|{{{2|}}}|{{{3|}}}|{{{4|}}}|page={{{page|}}}}}
 }}
}}<includeonly>{{template other| [[Category:Interconnected templates]] }}</includeonly><noinclude>
{{Documentation}}
<!-- Add categories to the /doc subpage; interwikis go to Wikidata, thank you! -->
</noinclude>

